  const predictionId = vote.predictionId;
  const userVote = vote.vote.toUpperCase();

  // Store vote in database (mock for now)
  const voteRecord = {
    userId,
    predictionId,
    vote: userVote,
    timestamp: new Date().toISOString()
  };

  // Calculate crowd consensus
  const totalVotes = 100; // Mock - fetch from DB
  const yesVotes = 73; // Mock - fetch from DB
  const yesPercent = (yesVotes / totalVotes) * 100;

  return {
    success: true,
    vote: userVote,
    crowdYesPercent: yesPercent.toFixed(1),
    crowdNoPercent: (100 - yesPercent).toFixed(1),
    message: userVote === 'YES' ? 
      `You voted YES! ${yesPercent.toFixed(0)}% of traders agree with you.` :
      `You voted NO! ${yesPercent.toFixed(0)}% say YES, you're contrarian.`,
    voteRecord
